import{_ as s,o as i,c as a,a as n}from"./chunks/framework.8tiMeCK-.js";const k=JSON.parse('{"title":"2.5  增删路由表项：在 FIB 里跳舞","description":"","frontmatter":{},"headers":[],"relativePath":"notes/linux_kernel_networking/ch02_5.md","filePath":"notes/linux_kernel_networking/ch02_5.md","lastUpdated":null}'),t={name:"notes/linux_kernel_networking/ch02_5.md"};function p(l,e,d,o,r,c){return i(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="_2-5-增删路由表项-在-fib-里跳舞" tabindex="-1">2.5 增删路由表项：在 FIB 里跳舞 <a class="header-anchor" href="#_2-5-增删路由表项-在-fib-里跳舞" aria-label="Permalink to &quot;2.5  增删路由表项：在 FIB 里跳舞&quot;">​</a></h1><p>上一节我们拆解了 Netlink 消息的头部和那些让人眼花缭乱的标志位。现在，是时候把这套理论扔进实战环境里了。</p><p>我们要看的是一个非常具体且高频的操作：<strong>向内核的路由表（FIB）里塞一条路由，或者删掉它。</strong></p><p>这是一个极佳的观察样本，因为它完整地展示了用户空间的一条命令，是如何通过 Netlink 这根线，一路拽着内核的 FIB 子系统满地跑的。而且，这里还藏着一个 Netlink 的杀手级特性——事件广播。</p><hr><h3 id="幕后推手-从-ip-命令到内核回调" tabindex="-1">幕后推手：从 <code>ip</code> 命令到内核回调 <a class="header-anchor" href="#幕后推手-从-ip-命令到内核回调" aria-label="Permalink to &quot;幕后推手：从 `ip` 命令到内核回调&quot;">​</a></h3><p>让我们先看增加路由。</p><p>你在命令行敲下这一行：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> route</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.2.11</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> via</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.2.20</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这行命令并没有直接去修改内存。它做的事情非常纯粹：在用户空间构建了一个 <code>RTM_NEWROUTE</code> 类型的 Netlink 消息，然后通过一个 <code>AF_NETLINK</code> 套接字，把它扔进了内核。</p><p>消息一旦越过边界，内核的 <code>rtnetlink</code> 机制就开始转动了。</p><ol><li><strong>接收</strong>：内核的 <code>rtnetlink</code> socket 把这条消息收进来，交给 <code>rtnetlink_rcv()</code> 方法。这是整个路由子系统的总入口。</li><li><strong>分发</strong>：<code>rtnetlink_rcv()</code> 看到消息类型是 <code>RTM_NEWROUTE</code>，就会去找谁来处理这件事。</li><li><strong>执行</strong>：最终，执行权被交到了 <code>net/ipv4/fib_frontend.c</code> 里的 <code>inet_rtm_newroute()</code> 函数手上。这是真正干脏活累活的地方。</li></ol><p><code>inet_rtm_newroute()</code> 并不只是简单地在数组里插一行——它得去操作 FIB（Forwarding Information Base，转发信息库）。这东西是内核路由决策的「圣经」，任何一点错误都会导致网络包要么送不出去，要么送去地狱。它会调用 <code>fib_table_insert()</code> 把这条路由真正写入硬件无关的路由表数据库里。</p><h3 id="广播这件事-别藏着掖着" tabindex="-1">广播这件事：别藏着掖着 <a class="header-anchor" href="#广播这件事-别藏着掖着" aria-label="Permalink to &quot;广播这件事：别藏着掖着&quot;">​</a></h3><p>如果事情到这里就结束，那 Netlink 只能算是个「高级 IOCTL」。</p><p>但 Netlink 不一样。<code>fib_table_insert()</code> 在把路由写进数据库之后，还要做另一件事——<strong>喊一嗓子</strong>。</p><p>它会调用 <code>rtmsg_fib()</code> 方法，并传入 <code>RTM_NEWROUTE</code> 参数。<code>rtmsg_fib()</code> 的任务不是操作路由，而是构建一个新的 Netlink 通知消息，然后调用 <code>rtnl_notify()</code>。</p><p>这一声「喊」，是发给 <code>RTNLGRP_IPV4_ROUTE</code> 这个多播组的。</p><p>这就像是在一个嘈杂的房间里，有人喊了一句：「嘿，大家注意，刚才加了一条 192.168.2.11 的路由！」。所有「订阅」了这个频道的人都能听到。</p><ul><li><code>iproute2</code> 套件里的工具在听。</li><li>用户空间的高级路由守护进程（像 <code>xorp</code> 或者 <code>bird</code>）也在听。</li><li>甚至内核里的其他模块，如果也注册了这个 group，同样能听到。</li></ul><p>这种「一边干活一边广播」的设计，是现代 Linux 网络管理的基础。它意味着用户空间的守护进程不需要轮询内核去查表变更，内核会主动推送。</p><hr><h3 id="删除路由-同样的剧本-不同的结局" tabindex="-1">删除路由：同样的剧本，不同的结局 <a class="header-anchor" href="#删除路由-同样的剧本-不同的结局" aria-label="Permalink to &quot;删除路由：同样的剧本，不同的结局&quot;">​</a></h3><p>删除操作几乎是一模一样的流程，只是换了几个名词。</p><p>你执行：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> route</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> del</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.2.11</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这次，<code>ip</code> 命令生成的是 <code>RTM_DELROUTE</code> 消息。</p><ol><li>消息飞进内核，再次命中 <code>rtnetlink_rcv()</code>。</li><li>这次它被分发到 <code>inet_rtm_delroute()</code> 回调函数（同样在 <code>fib_frontend.c</code> 里）。</li><li><code>inet_rtm_delroute()</code> 调用 <code>fib_table_delete()</code> 从 FIB 中抹去这条记录。</li><li>同样，这里会调用 <code>rtmsg_fib()</code>，只不过这次传入的是 <code>RTM_DELROUTE</code>。</li><li><code>rtnl_notify()</code> 再次出发，向 <code>RTNLGRP_IPV4_ROUTE</code> 广播：「嘿，大家注意，那条路由刚才删掉了。」</li></ol><p>你会发现，内核在处理「增」和「删」的时候，逻辑是对称的，侧重点都是：<strong>既要完成实际的数据结构操作，也要确保订阅者收到通知。</strong></p><hr><h3 id="实战验证-监听内核的心跳" tabindex="-1">实战验证：监听内核的心跳 <a class="header-anchor" href="#实战验证-监听内核的心跳" aria-label="Permalink to &quot;实战验证：监听内核的心跳&quot;">​</a></h3><p>光说不练是假把式。让我们来亲眼看看这个广播机制。</p><p>我们需要两个终端。这就好比你要验证房间里有没有人喊话，最好的办法就是自己带个收音机进去。</p><p><strong>终端 1：开启监听</strong></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> monitor</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> route</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这个命令启动了一个后台守护进程。它做了什么？它打开了一个 Netlink socket，并且执行了 <code>setsockopt()</code> 来加入 <code>RTNLGRP_IPV4_ROUTE</code> 多播组。现在，它正竖着耳朵等消息呢。</p><p><strong>终端 2：制造事件</strong></p><p>现在我们在第二个终端里，随便加一条路由：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> route</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.1.10</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> via</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.2.200</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这一瞬间，<code>ip</code> 命令发请求，内核处理请求，然后内核广播通知。</p><p><strong>回到终端 1</strong>，你应该会立即看到一行输出：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>192.168.1.10 via 192.168.2.200 dev em1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>看到了吗？这不是你敲的命令，这是内核广播回来的通知。你的监听进程收到了内核的 <code>rtnl_notify()</code>，并把它打印了出来。</p><p>接下来，在终端 2 删掉它：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> route</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> del</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.1.10</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>终端 1 会立刻显示：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Deleted 192.168.1.10 via 192.168.2.200 dev em1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>注意那个 <code>Deleted</code> 前缀——这是 <code>ip monitor</code> 的友善提示，它识别出了广播消息类型是 <code>RTM_DELROUTE</code>。</p><h3 id="更多的频道-链路与-vlan" tabindex="-1">更多的频道：链路与 VLAN <a class="header-anchor" href="#更多的频道-链路与-vlan" aria-label="Permalink to &quot;更多的频道：链路与 VLAN&quot;">​</a></h3><p>路由不是唯一能被广播的东西。<code>rtnetlink</code> 定义了各种各样的多播组。</p><p>你可以试试监听「链路」层的事件。在终端 1 执行：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> monitor</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> link</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这会让 Netlink socket 加入 <code>RTNLGRP_LINK</code> 组。只要网卡接口状态发生任何变化——UP/DOWN、新增 VLAN、添加 Bridge——你都能抓到。</p><p>现在去终端 2 试着加一个 VLAN 接口：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vconfig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> eth1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 200</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>终端 1 会瞬间刷出一大堆信息：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>4: eth1.200@eth1: &lt;BROADCAST,MULTICAST&gt; mtu 1500 qdisc noop state DOWN</span></span>\n<span class="line"><span>    link/ether 00:e0:4c:53:44:58 brd ff:ff:ff:ff:ff:ff</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>再加一个网桥试试：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> addbr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mybr</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>终端 1 继续跟进：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>5: mybr: &lt;BROADCAST,MULTICAST&gt; mtu 1500 qdisc noop state DOWN</span></span>\n<span class="line"><span>    link/ether a2:7c:be:62:b5:b6 brd ff:ff:ff:ff:ff:ff</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这就是为什么像 NetworkManager 这种工具能反应那么快——它们根本不需要去轮询 <code>/sys</code> 下的文件，它们只是静静地坐在 Netlink socket 旁边，等着内核告诉它们发生了什么。</p><hr><h3 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h3><p>走到这里，你已经看透了 Netlink Sockets 的全套把戏：</p><ol><li>它是一个基于 Socket 的标准 IPC 通道，取代了老旧的 IOCTL。</li><li>它有严格的消息格式（头部 + TLV 属性），能承载复杂的网络配置。</li><li>最重要的是，它是<strong>多播</strong>的。内核不只是被动接收命令，它还会主动向订阅者广播网络拓扑的变更。</li></ol><p>这套机制构成了现代 Linux 网络管理的基石。无论是 <code>ip</code> 命令，还是底层的 <code>rtnetlink</code>，本质上都在玩这一套规则。</p><p>但是，有一个问题。</p><p>如果你是内核开发者，你想给自己写的某个非标准内核模块加一个 Netlink 接口，你会怎么做？<code>rtnetlink</code> 是给网络子系统用的，你不能把你的随机硬件控制消息硬塞进 <code>RTM_NEWROUTE</code> 这种类型里。</p><p>32 个标准 Netlink 协议族的位置其实是很紧缺的。为了解决这个「地址空间危机」，内核后来引入了扩展机制。</p><p>下一节，我们要谈谈 <strong>Generic Netlink</strong>——这是为了解决「插座不够用了」这个问题而设计的终极多路复用方案。</p>',71)])])}const b=s(t,[["render",p]]);export{k as __pageData,b as default};
